def graph_diameter(spec: dict) -> int:
    """Diameter of an undirected connected graph: the largest shortest-path hop distance over all node pairs."""
    edges = spec["edges"]
    adj = {}
    for pr in edges:
        u, v = str(pr[0]), str(pr[1])
        adj.setdefault(u, []).append(v)
        adj.setdefault(v, []).append(u)
    diam = 0
    for s in sorted(adj.keys()):
        dist = {s: 0}
        frontier = [s]
        while frontier:
            nxt = []
            for u in frontier:
                for v in adj[u]:
                    if v not in dist:
                        dist[v] = dist[u] + 1
                        nxt.append(v)
            frontier = nxt
        diam = max(diam, max(dist.values()))
    return diam

