    for pr in edges {
        nodes[str(pr[0])] ++> nodes[str(pr[1])];
        nodes[str(pr[1])] ++> nodes[str(pr[0])];
    }
    diam: int = 0;
    for s in sorted(nodes.keys()) {
        for nm in nodes.keys() { nodes[nm].dist = -1; }
