def count_cut_vertices(spec: dict) -> int:
    """Count articulation points: nodes whose removal disconnects the undirected connected graph."""
    edges = spec["edges"]
    adj = {}
    for pr in edges:
        u, v = str(pr[0]), str(pr[1])
        adj.setdefault(u, []).append(v)
        adj.setdefault(v, []).append(u)
    names = sorted(adj.keys())
    n = len(names)
    cut = 0
    for c in names:
        start = next(x for x in names if x != c)
        seen = {start}
        stack = [start]
        while stack:
            u = stack.pop()
            for v in adj[u]:
                if v != c and v not in seen:
                    seen.add(v)
                    stack.append(v)
        if len(seen) != n - 1:
            cut += 1
    return cut

