    edges: list = list(spec["edges"]);
    nodes: dict = {};
    for pr in edges {
        for nm in [str(pr[0]), str(pr[1])] {
            if nm not in nodes { nodes[nm] = Spot(name=nm); }
        }
    }
    for pr in edges {
        nodes[str(pr[0])] ++> nodes[str(pr[1])];
        nodes[str(pr[1])] ++> nodes[str(pr[0])];
    }
    names: list = sorted(nodes.keys());
    n: int = len(names);
    cut: int = 0;
    for c in names {
        for nm in names { nodes[nm].seen = False; }
        start: str = "";
        for x in names {
            if x != c and start == "" { start = x; }
        }
        w = nodes[start] spawn Probe(blocked=c);
        if w.count != n - 1 { cut += 1; }
    }
    return cut;
}

