def weighted_median_stop(spec: dict) -> str {
    stops: list = list(spec["stops"]);
    lengths: list = list(spec["lengths"]);
    nodes: dict = {};
    for nm in stops { nodes[nm] = Stop(name=str(nm)); }
    for i in range(len(lengths)) {
        nodes[stops[i]] +>:Leg(length=int(lengths[i])):+> nodes[stops[i + 1]];
    }
    total: int = 0;
    for x in lengths { total += int(x); }
    w = nodes[stops[0]] spawn Median(total=total);
    return w.result;
}

