def count_st_paths(spec: dict) -> int:
    """Count the distinct directed paths from start to target in a DAG."""
    adj = spec["adj"]
    target = spec["target"]
    def walk(u):
        if u == target:
            return 1
        return sum(walk(v) for v in adj.get(u, []))
    return walk(spec["start"])

