def is_bipartite(spec: dict) -> str:
    """Return 'yes' if the undirected connected graph is 2-colorable, else 'no'."""
    edges = spec["edges"]
    adj = {}
    for pr in edges:
        u, v = str(pr[0]), str(pr[1])
        adj.setdefault(u, []).append(v)
        adj.setdefault(v, []).append(u)
    start = sorted(adj.keys())[0]
    color = {start: 0}
    frontier = [start]
    ok = True
    while frontier:
        nxt = []
        for u in frontier:
            for v in adj[u]:
                if v not in color:
                    color[v] = 1 - color[u]
                    nxt.append(v)
                elif color[v] == color[u]:
                    ok = False
        frontier = nxt
    return "yes" if ok else "no"

