def critical_path_cost(spec: dict) -> int:
    """Maximum total edge weight over all directed paths that begin at start in a weighted DAG."""
    adj = spec["adj"]
    def walk(u):
        best = 0
        for pr in adj.get(u, []):
            cand = int(pr[1]) + walk(str(pr[0]))
            if cand > best:
                best = cand
        return best
    return walk(spec["start"])

