def kth_nearest(spec: dict) -> str:
    """Name of the k-th nearest node reachable from start by hop distance (ties alphabetical, start excluded)."""
    adj = spec["adj"]
    start = spec["start"]
    k = spec["k"]
    dist = {start: 0}
    frontier = [start]
    while frontier:
        nxt = []
        for u in frontier:
            for v in adj.get(u, []):
                if v not in dist:
                    dist[v] = dist[u] + 1
                    nxt.append(v)
        frontier = nxt
    ranked = sorted([d, n] for n, d in dist.items() if n != start)
    return ranked[k - 1][1]

