def euler_trail_check(spec: dict) -> str:
    """Return 'yes' if the undirected graph has an Euler trail: it is connected and has 0 or 2 odd-degree nodes."""
    edges = spec["edges"]
    adj = {}
    for pr in edges:
        u, v = str(pr[0]), str(pr[1])
        adj.setdefault(u, []).append(v)
        adj.setdefault(v, []).append(u)
    names = sorted(adj.keys())
    start = names[0]
    seen = {start}
    stack = [start]
    while stack:
        u = stack.pop()
        for v in adj[u]:
            if v not in seen:
                seen.add(v)
                stack.append(v)
    if len(seen) != len(names):
        return "no"
    odd = sum(1 for n in names if len(adj[n]) % 2 == 1)
    return "yes" if odd in (0, 2) else "no"

