        nodes[str(pr[0])] ++> nodes[str(pr[1])];
        nodes[str(pr[1])] ++> nodes[str(pr[0])];
    }
    names: list = sorted(nodes.keys());
    w = nodes[names[0]] spawn Reach();
    if w.count != len(names) { return "no"; }
    odd: int = 0;
    for nm in names {
        nd = nodes[nm];
        if len([nd -->]) % 2 == 1 { odd += 1; }
    }
    if odd == 0 or odd == 2 { return "yes"; }
    return "no";
}

