def longest_increasing_path(spec: dict) -> int:
    """Most nodes on any path from start that only follows edges to strictly larger values."""
    adj = spec["adj"]
    vals = spec["vals"]
    def walk(u):
        best = 1
        for v in adj.get(u, []):
            if vals[v] > vals[u]:
                cand = 1 + walk(v)
                if cand > best:
                    best = cand
        return best
    return walk(spec["start"])

